#include <bits/stdc++.h>
using namespace std;
int main(){
    string c,k;
    cin>>k>>c;
    for(int i=0;i<k.size();i++)
        if(k[i]>='A' && k[i]<='Z')k[i]+=32;
    for(int i=0;i<c.size();i++){
        char p=k[i%k.size()],m;
        //cout<<p<<endl; 
        if(c[i]>='A' && c[i]<='Z')p-=32;
        if(c[i]>='a' && c[i]<='z'){
            m=(c[i]-'a')-(p-'a')+'a';
            while(m<'a')m+=26;
        }else{
            m=(c[i]-'A')-(p-'A')+'A';
            while(m<'A')m+=26;
        }
        cout<<m;
    }
    return 0;
}
